import React, {
	forwardRef,
	useEffect,
	useImperativeHandle,
	useRef,
	useState,
} from "react";

import "./TextInput.css";

const TextAreaHRM = forwardRef(({ placeholderCode, label, updChanges, init, width, type }, ref) => {
	
	const [initialize, setInitialize] = useState(false);
	const [txt, settxt] = useState("");
	const cmpRef = useRef("");

	useEffect(() => {
		if (!initialize) {
			setInitialize(true);
		}
    });
    
    useEffect(() => {
		if (init && init!==txt) {
            settxt(init);
			cmpRef.current.value = init;
			auto_grow(cmpRef.current)
		}
	},[init]);
	
	function auto_grow(element) {
		element.style.height = "5px";
		element.style.height = (element.scrollHeight)+"px";
	}
    

	const handleInput = (v) => {
		settxt(v.target.value);
		auto_grow(v.target)
		if (typeof updChanges === "function") {

			updChanges(v.target.value);
		}
	};

	const handleKey = (v) => {
		
	};

	const clearTx = (v) => {
		settxt("");
		document.getElementById("SREsRA").value = "";
		cmpRef.current.value = "";
		if (typeof updChanges === "function") {
			updChanges("");
		}
	};

	useImperativeHandle(ref, () => ({
		clearTx() {
			clearTx();
		},
		init(v) {
			settxt(v);
		},
	}));

    return (
        <div>
			{label ?
            <p className="label">
                {label}
            </p>
			:null}
            <textarea
                style={width? {width: width}: null}
				ref={cmpRef}
				
				className="r7gAOb yyJm8b txtare"
				type={type || "text"}
				//aria-autocomplete="both"
				aria-haspopup="false"
				auto-capitalize="off"
				auto-complete="off"
				auto-correct="off"
				spell-check="false"
				placeholder={placeholderCode}
				onChange={handleInput}
				onKeyDown={handleKey}
			/>
        </div>
    )
})


export default TextAreaHRM;